import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { 
  Trash2, ArrowLeft, Save, Loader2, ImageIcon, Sparkles, Database, Calendar, Eraser, Send
} from 'lucide-react';

const GestionOfertas = () => {
  const { id: localId } = useParams();
  const navigate = useNavigate();
  
  // Estados
  const [filas, setFilas] = useState([{ id: Date.now(), producto: '', precio: '', stock: '', foto: null }]);
  const [galeria, setGaleria] = useState([]);
  const [loading, setLoading] = useState(false);
  const [fechas, setFechas] = useState({ inicio: '', fin: '' });
  const [showGaleria, setShowGaleria] = useState(false);

  const API_URL = "http://localhost:5000"; 
  const CLOUD_NAME = "dwpgncjgn";

  // Cargar Galería para match de fotos
  useEffect(() => {
    axios.get(`${API_URL}/api/galeria`).then(res => setGaleria(res.data));
  }, []);

  const buscarMatch = (texto) => {
    if (!texto || texto.length < 3) return null;
    const t = texto.toLowerCase();
    const palabras = t.split(' ').filter(p => p.length > 1);
    return galeria.find(f => palabras.every(p => f.nombreReferencia.includes(p)));
  };

  // --- LÓGICA DE PEGAR DESDE EXCEL ---
  const handlePaste = (e) => {
    e.preventDefault();
    const paste = e.clipboardData.getData('text');
    const rows = paste.split('\n').filter(row => row.trim() !== '');
    
    const nuevasFilas = rows.map(row => {
      const columns = row.split('\t'); // Excel separa por tabs
      const nombreProd = columns[0] || '';
      return {
        id: Math.random(),
        producto: nombreProd,
        precio: columns[1] || '',
        stock: columns[2] || '',
        foto: buscarMatch(nombreProd)
      };
    });

    setFilas(nuevasFilas);
  };

  const updateFila = (id, field, value) => {
    setFilas(prev => prev.map(f => {
      if (f.id === id) {
        const upd = { ...f, [field]: value };
        if (field === 'producto') upd.foto = buscarMatch(value);
        return upd;
      }
      return f;
    }));
  };

  const publicarTodo = async () => {
    if (!fechas.inicio || !fechas.fin) return alert("Debes definir inicio y fin de la oferta");
    setLoading(true);
    try {
      const promesas = filas.map(f => {
        if (!f.producto || !f.precio) return null;
        return axios.post(`${API_URL}/api/ofertas`, {
          producto: f.producto,
          precioNuevo: Number(f.precio),
          stock: Number(f.stock) || 0,
          publicId: f.foto ? f.foto.publicId : 'placeholder_id',
          local: localId,
          fechaInicio: fechas.inicio,
          fechaFin: fechas.fin,
          publicado: true
        });
      });
      await Promise.all(promesas.filter(p => p !== null));
      alert("¡Ofertas publicadas con éxito!");
      setFilas([{ id: Date.now(), producto: '', precio: '', stock: '', foto: null }]);
    } catch (e) {
      alert("Error al publicar");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={containerStyle}>
      {/* HEADER */}
      <div style={headerStyle}>
        <button onClick={() => navigate('/dashboard')} style={btnBack}><ArrowLeft size={18}/> Volver</button>
        <div style={{display:'flex', gap:'10px'}}>
            <button onClick={() => setFilas([{ id: Date.now(), producto: '', precio: '', stock: '', foto: null }])} style={btnDanger}><Eraser size={18}/> Borrar Tabla</button>
            <button onClick={publicarTodo} style={btnSuccess} disabled={loading}>
                {loading ? <Loader2 className="animate-spin"/> : <Send size={18}/>} Publicar Ofertas
            </button>
        </div>
      </div>

      <div style={mainGrid}>
        {/* COLUMNA IZQUIERDA: CONFIG Y TABLA */}
        <div style={leftCol}>
          <div style={cardConfig}>
            <h3><Calendar size={20}/> Vigencia de las Ofertas</h3>
            <div style={inputGroup}>
              <div><label>Inicio</label><input type="date" value={fechas.inicio} onChange={e=>setFechas({...fechas, inicio:e.target.value})} style={dateInput}/></div>
              <div><label>Fin</label><input type="date" value={fechas.fin} onChange={e=>setFechas({...fechas, fin:e.target.value})} style={dateInput}/></div>
            </div>
          </div>

          <div style={tableWrapper}>
            <table style={excelTable}>
              <thead>
                <tr>
                  <th>Foto</th>
                  <th>Producto (Pega aquí desde Excel)</th>
                  <th>Precio $</th>
                  <th>Stock</th>
                  <th></th>
                </tr>
              </thead>
              <tbody onPaste={handlePaste}>
                {filas.map((f, index) => (
                  <tr key={f.id}>
                    <td>
                        <div style={miniPreview}>
                            {f.foto ? <img src={`https://res.cloudinary.com/${CLOUD_NAME}/image/upload/w_50/v1/${f.foto.publicId}`} style={imgSmall}/> : <ImageIcon size={16} color="#ccc"/>}
                        </div>
                    </td>
                    <td>
                        <input 
                            style={inputInvisible} 
                            value={f.producto} 
                            placeholder={index === 0 ? "Haz clic aquí y PEGA tus celdas de Excel..." : ""}
                            onChange={e => updateFila(f.id, 'producto', e.target.value)}
                        />
                        {f.foto && <span style={matchText}><Sparkles size={10}/> Match!</span>}
                    </td>
                    <td><input style={inputInvisible} type="number" value={f.precio} onChange={e => updateFila(f.id, 'precio', e.target.value)}/></td>
                    <td><input style={inputInvisible} type="number" value={f.stock} onChange={e => updateFila(f.id, 'stock', e.target.value)}/></td>
                    <td><button onClick={() => setFilas(filas.filter(row => row.id !== f.id))} style={btnDel}><Trash2 size={14}/></button></td>
                  </tr>
                ))}
              </tbody>
            </table>
            <button onClick={() => setFilas([...filas, { id: Date.now(), producto: '', precio: '', stock: '', foto: null }])} style={btnAdd}><Plus size={14}/> Añadir fila manual</button>
          </div>
        </div>
      </div>
    </div>
  );
};

